// auping-popup.js — Bylder × Auping Rotterdam Centrum
// Gebruik: <script src="/auping-popup.js"></script> voor </body>

(function() {
  if (localStorage.getItem('aupingPopupDismissed')) return;

  const style = document.createElement('style');
  style.textContent = `
    #aupingPopup {
      display: none;
      position: fixed;
      inset: 0;
      background: rgba(0,0,0,0.6);
      backdrop-filter: blur(8px);
      -webkit-backdrop-filter: blur(8px);
      z-index: 9999;
      align-items: center;
      justify-content: center;
      padding: 16px;
    }
    #aupingPopup.open { display: flex; }
    #aupingPopupInner {
      background: #fff;
      border-radius: 20px;
      max-width: 480px;
      width: 100%;
      overflow: hidden;
      box-shadow: 0 24px 80px rgba(0,0,0,0.35);
      animation: aupingPop 0.4s cubic-bezier(0.34,1.56,0.64,1);
      max-height: 92vh;
      overflow-y: auto;
      -webkit-overflow-scrolling: touch;
    }
    @keyframes aupingPop {
      from { opacity:0; transform:scale(0.88) translateY(20px); }
      to   { opacity:1; transform:scale(1) translateY(0); }
    }
    #aupingPopupHeader {
      background: #003B6F;
      padding: 24px 28px 20px;
      position: relative;
    }
    #aupingPopupClose {
      position: absolute;
      top: 14px; right: 14px;
      background: rgba(255,255,255,0.15);
      border: none;
      color: #fff;
      width: 34px; height: 34px;
      border-radius: 50%;
      cursor: pointer;
      font-size: 20px;
      display: flex; align-items: center; justify-content: center;
      line-height: 1;
      min-width: 34px;
    }
    #aupingPopupClose:hover { background: rgba(255,255,255,0.25); }
    .ap-logo-row { display: flex; align-items: center; gap: 10px; margin-bottom: 14px; flex-wrap: wrap; }
    .ap-logo { background: #fff; border-radius: 5px; padding: 5px 10px; font-size: 16px; font-weight: 900; color: #003B6F; letter-spacing: 0.1em; font-family: sans-serif; }
    .ap-x { color: rgba(255,255,255,0.4); font-size: 14px; }
    .ap-bylder { background: rgba(61,90,62,0.9); border-radius: 5px; padding: 5px 10px; font-size: 13px; font-weight: 800; color: #F5F0E8; font-family: sans-serif; }
    .ap-sub { font-size: 11px; color: rgba(255,255,255,0.5); text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px; font-family: monospace; }
    .ap-title { font-size: 18px; font-weight: 800; color: #fff; line-height: 1.25; font-family: sans-serif; }
    #aupingPopupBody { padding: 20px 24px; display: flex; flex-direction: column; gap: 10px; }
    .ap-voordeel {
      display: flex; align-items: flex-start; gap: 12px;
      padding: 12px 14px;
      background: #E8EEF5;
      border-radius: 10px;
    }
    .ap-num {
      width: 32px; height: 32px; min-width: 32px;
      background: #003B6F;
      border-radius: 7px;
      display: flex; align-items: center; justify-content: center;
      font-size: 14px; font-weight: 900; color: #fff;
      font-family: monospace;
    }
    .ap-voordeel-title { font-size: 14px; font-weight: 800; color: #003B6F; margin-bottom: 2px; font-family: sans-serif; }
    .ap-voordeel-desc { font-size: 12px; color: #2D4A6B; line-height: 1.45; font-family: sans-serif; }

    /* ACCOUNT CTA — het belangrijkste blok */
    .ap-account-box {
      background: linear-gradient(135deg, #003B6F, #0066B3);
      border-radius: 12px;
      padding: 16px 18px;
      margin-top: 2px;
    }
    .ap-account-label {
      font-size: 11px; font-family: monospace; text-transform: uppercase;
      letter-spacing: 0.08em; color: rgba(255,255,255,0.55); margin-bottom: 6px;
    }
    .ap-account-title {
      font-size: 15px; font-weight: 800; color: #fff;
      font-family: sans-serif; margin-bottom: 4px;
    }
    .ap-account-desc {
      font-size: 12px; color: rgba(255,255,255,0.65);
      line-height: 1.5; font-family: sans-serif; margin-bottom: 12px;
    }
    .ap-account-cta {
      display: block;
      background: #fff;
      color: #003B6F;
      padding: 11px 16px;
      border-radius: 8px;
      font-size: 14px; font-weight: 800;
      text-decoration: none;
      text-align: center;
      font-family: sans-serif;
    }
    .ap-account-cta:hover { background: #E8EEF5; }
    .ap-account-login {
      font-size: 12px; color: rgba(255,255,255,0.5);
      text-align: center; margin-top: 8px;
      font-family: sans-serif;
    }
    .ap-account-login a { color: rgba(255,255,255,0.75); }

    .ap-disclaimer { font-size: 11px; color: rgba(0,59,111,0.4); text-align: center; font-family: monospace; text-transform: uppercase; letter-spacing: 0.06em; }
    .ap-meer {
      display: block;
      border: 1.5px solid rgba(0,59,111,0.2);
      color: #003B6F;
      padding: 11px;
      border-radius: 10px;
      font-size: 13px; font-weight: 700;
      text-decoration: none; text-align: center;
      font-family: sans-serif;
    }
    .ap-meer:hover { background: #E8EEF5; }
    .ap-dismiss {
      background: none; border: none;
      color: rgba(61,46,30,0.35);
      font-size: 12px; cursor: pointer;
      font-family: sans-serif; padding: 4px;
      text-align: center; width: 100%;
    }
    @media (max-width: 480px) {
      #aupingPopupInner { border-radius: 16px; }
      #aupingPopupHeader { padding: 20px 18px 18px; }
      #aupingPopupBody { padding: 16px 16px; gap: 8px; }
      .ap-title { font-size: 16px; }
      .ap-account-title { font-size: 14px; }
    }
  `;
  document.head.appendChild(style);

  const popup = document.createElement('div');
  popup.id = 'aupingPopup';
  popup.innerHTML = `
    <div id="aupingPopupInner">
      <div id="aupingPopupHeader">
        <button id="aupingPopupClose" onclick="window.sluitAupingPopup()" aria-label="Sluiten">×</button>
        <div class="ap-logo-row">
          <img src="data:image/png;base64," alt="Auping" style="height:28px;width:auto;filter:brightness(0) invert(1);">
          <span class="ap-x">×</span>
          <div class="ap-bylder">Bylder.com</div>
        </div>
        <div class="ap-sub">Exclusief voor Bylder-leden · Rotterdam Centrum</div>
        <div class="ap-title">Drie voordelen die je<br>nergens anders krijgt</div>
      </div>
      <div id="aupingPopupBody">

        <div class="ap-voordeel">
          <div class="ap-num">1</div>
          <div>
            <div class="ap-voordeel-title">10% korting op alles</div>
            <div class="ap-voordeel-desc">Boxsprings, matrassen, bedframes — geen minimumbesteding.</div>
          </div>
        </div>

        <div class="ap-voordeel">
          <div class="ap-num">2</div>
          <div>
            <div class="ap-voordeel-title">🛏️ Gratis leenbed tijdens levertijd</div>
            <div class="ap-voordeel-desc">Geen nacht op de grond na je verhuizing. <strong>Vanaf €5.000 besteding.</strong></div>
          </div>
        </div>

        <div class="ap-voordeel">
          <div class="ap-num">3</div>
          <div>
            <div class="ap-voordeel-title">🏨 Gratis overnachting Hotel Haverkist</div>
            <div class="ap-voordeel-desc">Voor 2 personen incl. ontbijt in Den Bosch, t.w.v. €199. <strong>Vanaf €6.500 besteding.</strong></div>
          </div>
        </div>

        <div class="ap-disclaimer">Alleen geldig bij Auping Rotterdam Centrum</div>

        <!-- ACCOUNT CTA — verplicht om voordelen te ontvangen -->
        <div class="ap-account-box">
          <div class="ap-account-label">Stap 1 — account aanmaken</div>
          <div class="ap-account-title">Maak een Bylder account aan om deze voordelen te ontvangen</div>
          <div class="ap-account-desc">Je Bylder account geeft je toegang tot de Auping voucher. Toon de voucher in de winkel — dan worden alle voordelen direct toegepast.</div>
          <a href="/betalen/" class="ap-account-cta" onclick="window.sluitAupingPopup()">Account aanmaken voor €99 →</a>
          <div class="ap-account-login">Al lid? <a href="https://app.bylder.com" onclick="window.sluitAupingPopup()">Log in en activeer je voucher</a></div>
        </div>

        <a href="/vouchers/auping/" class="ap-meer" onclick="window.sluitAupingPopup()">Meer over de Auping voordelen →</a>
        <button class="ap-dismiss" onclick="window.sluitAupingPopup();localStorage.setItem('aupingPopupDismissed','1')">Niet meer tonen</button>
      </div>
    </div>
  `;
  document.body.appendChild(popup);

  popup.addEventListener('click', function(e) {
    if (e.target === popup) window.sluitAupingPopup();
  });

  window.sluitAupingPopup = function() {
    popup.classList.remove('open');
  };

  // Toon na 4 seconden
  setTimeout(function() {
    popup.classList.add('open');
  }, 4000);
})();
